#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[129];
        scanf("%s", S);
        int i = 0;
        while (S[i] != 'B') {
            if (S[i] == 'W') {
                printf("W\n");
                break;
            }
            i++;
        }
        if (S[i] == 'B') {
            printf("B\n");
        }
    }
    return 0;
}

