import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            String S = sc.nextLine();
            int i = 0;
            while (S.charAt(i) != 'B') {
                if (S.charAt(i) == 'W') {
                    System.out.println("W");
                    break;
                }
                i++;
            }
            if (S.charAt(i) == 'B') {
                System.out.println("B");
            }
        }
    }
}

